mapper.select:
SELECT COALESCE(
    (
        (SELECT COUNT(*)
         FROM `bls_table_usage`
         WHERE start_time >= #{date}
           AND start_time < DATE_ADD(#{date}, INTERVAL 1 DAY)

             AND store_id IN

                 #{storeId}


           AND status = 1)
        * 100.0
        /
        NULLIF(
            (SELECT COUNT(*)
             FROM bls_table
             WHERE is_delete = 0

                 AND store_id IN

                     #{storeId}


            ), 0)
    ), 0
) AS usage_rate

SELECT t.id as tableId, concat(t.table_prefix, t.table_numeric) as tableNumber, t.store_id as storeId, s.name as storeName, COUNT(tu.id) as usageCount, COALESCE(SUM(tu.duration), 0) as totalDuration, COALESCE(SUM(o.actual_amount), 0) as totalRevenue FROM bls_table t JOIN bls_store s ON t.store_id = s.id LEFT JOIN bls_table_usage tu ON t.id = tu.table_id AND tu.start_time >= #{startDate} AND tu.start_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY) LEFT JOIN `bls_order` o ON tu.order_id = o.id AND o.status = 1 WHERE t.is_delete = 0
AND t.store_id IN
#{storeId}
GROUP BY t.id, t.table_prefix, t.table_numeric, t.store_id, s.name ORDER BY totalRevenue DESC LIMIT #{limit}

SELECT COUNT(*) FROM bls_table WHERE is_delete = 0 and status in (0 ,1)
AND store_id IN
#{storeId}

SELECT COUNT(*) FROM bls_table WHERE is_delete = 0 and status = 1
AND store_id IN
#{storeId}

SELECT COALESCE(AVG(duration), 0)
FROM bls_table_usage
WHERE start_time >= #{startDate}
AND start_time < DATE_ADD(#{startDate}, INTERVAL 1 DAY)

    AND store_id IN

        #{storeId}
